import"https://cdn.tailwindcss.com";document.getElementById("loginForm").addEventListener("submit",async n=>{n.preventDefault();const a=document.getElementById("username").value,o=document.getElementById("password").value,t=document.getElementById("errorMessage"),e=document.getElementById("loginBtn");t.classList.add("hidden"),e.disabled=!0,e.textContent="登录中...",e.classList.add("opacity-70","cursor-not-allowed");try{const s=await(await fetch("/api/admin/login",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:a,password:o})})).json();s.success?(localStorage.setItem("token",s.token),window.location.href="/admin/services"):(t.textContent=s.error||"登录失败，请检查用户名和密码",t.classList.remove("hidden"),e.disabled=!1,e.textContent="登 录",e.classList.remove("opacity-70","cursor-not-allowed"))}catch{t.textContent="网络错误，请稍后重试",t.classList.remove("hidden"),e.disabled=!1,e.textContent="登 录",e.classList.remove("opacity-70","cursor-not-allowed")}});tailwind.config={theme:{extend:{animation:{"fade-in":"fadeIn 0.6s ease-out","slide-up":"slideUp 0.5s ease-out",float:"float 6s ease-in-out infinite"},keyframes:{fadeIn:{"0%":{opacity:"0"},"100%":{opacity:"1"}},slideUp:{"0%":{opacity:"0",transform:"translateY(20px)"},"100%":{opacity:"1",transform:"translateY(0)"}},float:{"0%, 100%":{transform:"translateY(0)"},"50%":{transform:"translateY(-10px)"}}}}}};
